const ptOriginal = {};
document.querySelectorAll('[data-i18n]').forEach(el => ptOriginal[el.dataset.i18n] = el.textContent.trim());
document.querySelectorAll('[data-i18n-alt]').forEach(el => ptOriginal[el.dataset.i18nAlt] = (el.getAttribute('alt') || '').trim());
translations.pt = ptOriginal;

const LANGUAGE_STORAGE_KEY = 'trafo-language';
const SUPPORTED_LANGUAGES = ['es', 'en', 'pt'];

function readStoredLanguage() {
  try {
    return window.localStorage.getItem(LANGUAGE_STORAGE_KEY);
  } catch {
    return null;
  }
}

function storeLanguage(lang) {
  try {
    window.localStorage.setItem(LANGUAGE_STORAGE_KEY, lang);
  } catch {
    // Alguns modos de privacidade bloqueiam o armazenamento local.
  }
}

function setLanguage(lang, { persist = true } = {}) {
  const selectedLanguage = SUPPORTED_LANGUAGES.includes(lang) ? lang : 'es';
  const dict = translations[selectedLanguage] || translations.es;
  document.documentElement.lang = selectedLanguage === 'pt' ? 'pt-BR' : selectedLanguage;
  document.querySelectorAll('[data-i18n]').forEach(el => {
    const key = el.dataset.i18n;
    if (dict[key]) el.textContent = dict[key];
  });
  document.querySelectorAll('[data-i18n-alt]').forEach(el => {
    const key = el.dataset.i18nAlt;
    if (dict[key]) el.setAttribute('alt', dict[key]);
  });
  document.querySelectorAll('.lang-btn').forEach(btn => {
    const active = btn.dataset.lang === selectedLanguage;
    btn.classList.toggle('active', active);
    btn.setAttribute('aria-pressed', String(active));
  });
  if (persist) storeLanguage(selectedLanguage);
}

document.querySelectorAll('.lang-btn').forEach(btn =>
  btn.addEventListener('click', () => setLanguage(btn.dataset.lang))
);

// Primeira visita: espanhol. Visitas seguintes: último idioma escolhido.
const savedLanguage = readStoredLanguage();
setLanguage(SUPPORTED_LANGUAGES.includes(savedLanguage) ? savedLanguage : 'es', { persist: false });

const cadLightbox = document.getElementById('cad-lightbox');
const cadLightboxImage = cadLightbox?.querySelector('img');
const cadLightboxCaption = cadLightbox?.querySelector('figcaption');
const cadLightboxClose = cadLightbox?.querySelector('.cad-lightbox-close');

document.querySelectorAll('[data-cad-viewer]').forEach(button => {
  button.addEventListener('click', () => {
    const image = button.querySelector('img');
    const caption = button.closest('.integration-model-card')?.querySelector('figcaption strong')?.textContent.trim() || '';
    if (!image) return;

    if (!cadLightbox || !cadLightboxImage || typeof cadLightbox.showModal !== 'function') {
      window.open(image.currentSrc || image.src, '_blank', 'noopener,noreferrer');
      return;
    }

    cadLightboxImage.src = image.currentSrc || image.src;
    cadLightboxImage.alt = image.alt;
    cadLightboxCaption.textContent = caption;
    cadLightbox.showModal();
  });
});

cadLightboxClose?.addEventListener('click', () => cadLightbox.close());
cadLightbox?.addEventListener('click', event => {
  if (event.target === cadLightbox) cadLightbox.close();
});

const header = document.querySelector('.site-header');
if (header) {
  const updateHeader = () => header.classList.toggle('scrolled', window.scrollY > 24);
  updateHeader();
  window.addEventListener('scroll', updateHeader, { passive: true });
}

const toggle = document.querySelector('.menu-toggle');
const nav = document.querySelector('.main-nav');
const companyDropdown = document.querySelector('.nav-dropdown');
const companyDropdownToggle = document.querySelector('.nav-dropdown-toggle');
if (companyDropdown && companyDropdownToggle) {
  companyDropdownToggle.addEventListener('click', event => {
    event.stopPropagation();
    const open = companyDropdown.classList.toggle('open');
    companyDropdownToggle.setAttribute('aria-expanded', String(open));
  });
  document.addEventListener('click', event => {
    if (!companyDropdown.contains(event.target)) {
      companyDropdown.classList.remove('open');
      companyDropdownToggle.setAttribute('aria-expanded', 'false');
    }
  });
}

if (toggle && nav) toggle.addEventListener('click', () => {
  const open = nav.classList.toggle('open');
  toggle.setAttribute('aria-expanded', String(open));
});
if (nav) nav.querySelectorAll('a').forEach(a => a.addEventListener('click', () => {
  nav.classList.remove('open');
  if (companyDropdown) companyDropdown.classList.remove('open');
  if (companyDropdownToggle) companyDropdownToggle.setAttribute('aria-expanded', 'false');
  if (toggle) toggle.setAttribute('aria-expanded', 'false');
}));

document.addEventListener('keydown', event => {
  if (event.key !== 'Escape') return;
  if (nav) nav.classList.remove('open');
  if (toggle) toggle.setAttribute('aria-expanded', 'false');
  if (companyDropdown) companyDropdown.classList.remove('open');
  if (companyDropdownToggle) companyDropdownToggle.setAttribute('aria-expanded', 'false');
});

const revealElements = document.querySelectorAll('.reveal');
if (typeof window.IntersectionObserver === 'function') {
  const observer = new IntersectionObserver(entries => entries.forEach(entry => {
    if (entry.isIntersecting) {
      entry.target.classList.add('visible');
      observer.unobserve(entry.target);
    }
  }), { threshold: .12 });
  revealElements.forEach(el => observer.observe(el));
} else {
  revealElements.forEach(el => el.classList.add('visible'));
}

const yearElement = document.getElementById('year');
if (yearElement) yearElement.textContent = new Date().getFullYear();

// Reposiciona links diretos depois que fontes e imagens terminam de carregar.
// Isso mantém o título do artigo visível abaixo do cabeçalho fixo.
function alignTechnicalContentAnchor() {
  if (!window.location.hash) return;

  let anchorId = '';
  try {
    anchorId = decodeURIComponent(window.location.hash.slice(1));
  } catch {
    anchorId = window.location.hash.slice(1);
  }

  const target = document.getElementById(anchorId);
  if (!target || !target.classList.contains('technical-article')) return;

  const root = document.documentElement;
  const previousBehavior = root.style.getPropertyValue('scroll-behavior');
  const previousPriority = root.style.getPropertyPriority('scroll-behavior');
  root.style.setProperty('scroll-behavior', 'auto', 'important');
  target.scrollIntoView({ behavior: 'auto', block: 'start' });
  if (previousBehavior) {
    root.style.setProperty('scroll-behavior', previousBehavior, previousPriority);
  } else {
    root.style.removeProperty('scroll-behavior');
  }
}

window.addEventListener('hashchange', alignTechnicalContentAnchor);
if (document.readyState === 'complete') {
  alignTechnicalContentAnchor();
} else {
  window.addEventListener('load', () => window.requestAnimationFrame(alignTechnicalContentAnchor), { once: true });
}

